319	double eval_lookahead(const GameState& state_after_tilt, int turn_T_of_candy_just_processed, int depth_remaining) {
320	    if (depth_remaining == 0 || turn_T_of_candy_just_processed == NUM_TURNS) {
321	        return state_after_tilt.evaluate();
322	    }
323	
324	    int num_empty = state_after_tilt.count_empty_cells();
325	    if (num_empty == 0) {
326	        return state_after_tilt.evaluate();
327	    }
328	
329	    int next_candy_flavor = G_FLAVOR_SEQUENCE[turn_T_of_candy_just_processed];
330	    int sample_count_param_idx = MAX_LOOKAHEAD_DEPTH - depth_remaining;
331	    int sample_count_this_depth = NUM_SAMPLES_CONFIG[sample_count_param_idx];
332	    int actual_num_samples = std::min(sample_count_this_depth, num_empty);
333	
334	    if (actual_num_samples == 0) {
335	         return state_after_tilt.evaluate();
336	    }
337	
338	    double sum_over_sampled_placements = 0.0;
339	    for (int s = 0; s < actual_num_samples; ++s) {
340	        int p_val;
341	        if (actual_num_samples == num_empty) {
342	            p_val = s + 1;
343	        } else {
344	            p_val = rng.uniform_int(1, num_empty);
345	        }
346	
347	        GameState S_after_placement = state_after_tilt;
348	        std::pair<int, int> candy_loc = S_after_placement.find_pth_empty_cell(p_val);
349	        S_after_placement.place_candy(candy_loc.first, candy_loc.second, next_candy_flavor);
350	        S_after_placement.turn_num_1_indexed = turn_T_of_candy_just_processed + 1;
351	
352	        double max_eval = std::numeric_limits<double>::lowest();
353	        for (int dir_idx = 0; dir_idx < NUM_DIRECTIONS; ++dir_idx) {
354	            GameState S_after_tilt = S_after_placement;
355	            S_after_tilt.apply_tilt(dir_idx);
356	            double val = eval_lookahead(S_after_tilt, S_after_placement.turn_num_1_indexed, depth_remaining - 1);
357	            if (val > max_eval) {
358	                max_eval = val;
359	            }
360	        }
361	        sum_over_sampled_placements += max_eval;
362	    }
363	
364	    return sum_over_sampled_placements / actual_num_samples;
365	}
