            for (int c_start = 0; c_start < GRID_SIZE; ++c_start) {
                if (board[r_start][c_start] != 0 && comp_id[r_start][c_start] == -1) {
                    int current_flavor = board[r_start][c_start];
                    int this_comp = num_comps++;
                    int comp_size = 0;
                    q_arr[0] = {r_start, c_start};
                    comp_id[r_start][c_start] = this_comp;
