                if (board[r][c] == 0) continue;
                int f = board[r][c];
                if (c + 1 < GRID_SIZE && board[r][c + 1] == f) count++;
                if (r + 1 < GRID_SIZE && board[r + 1][c] == f) count++;
            }
        }
